try {
    const response = await pm.sendRequest({
        url: "https://postman-echo.com/get",
        method: "GET"
    });

    console.log(response.json());
} catch (err) {
    console.error(err);
}

const creds = btoa(pm.environment.get("user") + ":" + pm.environment.get("pass"));
pm.request.headers.add({
    key: "Authorization",
    value: "Basic " + creds
});

const response = await pm.sendRequest({
    url: pm.environment.get("login_url"),
    method: "POST",
    header: { "Content-Type": "application/json" },
    body: { mode: "raw", raw: JSON.stringify({ user: "u", pass: "p" }) }
});
pm.environment.set("token", response.json().token);

pm.test("Your test name", function () {
    const jsonData = pm.response.json();
    pm.expect(jsonData.value).to.eql(100);
});

pm.test("Response time is less than 200ms", function () {
    pm.expect(pm.response.responseTime).to.be.below(200);
});

pm.test("Status code name has string", function () {
    pm.response.to.have.status("Created");
});

const tv4 = pm.require("tv4");
const schema = {
    "items": { "type": "boolean" }
};
const data1 = [true, false];
pm.test("Schema is valid", function () {
    pm.expect(tv4.validate(data1, schema)).to.be.true;
});

pm.test("Returns three items", function () {
    const arr = pm.response.json().items;
    pm.expect(arr).to.have.lengthOf(3);
});

// Specifier must be a string literal — Postmark scans the script
// statically and resolves the import before user code runs.
// Pin exact versions (X.Y.Z) for reproducibility.
const lodash = pm.require("npm:lodash@4.17.21");

const grouped = lodash.groupBy(pm.response.json().items, "status");
console.log(grouped);

const assert = pm.require("jsr:@std/assert@0.220.1");

pm.test("std/assert wired", function () {
    pm.expect(typeof assert.assertEquals).to.equal("function");
});

// 1. Settings → Private packages → npm → Add npm registry
//      Scope: @mycompany
//      URL:   https://npm.mycorp.io/
//      Auth:  Token (your CI read-only token)
// 2. Apply.
// 3. Public packages still resolve from registry.npmjs.org; only your
//    @scope routes to the private mirror.
const lodash = pm.require("npm:lodash@4.17.21");
const internal = pm.require("npm:@mycompany/auth-helpers@2.4.0");

pm.test("internal helpers wired", function () {
    pm.expect(typeof internal.signRequest).to.equal("function");
});

// JSR.io has no native private-package support. Most enterprises
// proxy JSR through an npm-compatible upstream (Cloudsmith,
// Artifactory). Add the proxy as a JSR scope row at
// Settings → Private packages → JSR and the same .npmrc machinery
// resolves jsr: specifiers transparently.
const stdFs = pm.require("jsr:@std/fs@1.0.0");
console.log(typeof stdFs.exists);

const jose = pm.require("npm:jose@5.2.0");
const token = pm.response.json().access_token;

const claims = jose.decodeJwt(token);
pm.environment.set("user_id", String(claims.sub || ""));
pm.test("Has subject claim", function () {
    pm.expect(claims).to.have.property("sub");
});

const { z } = pm.require("npm:zod@3.22.4");

const User = z.object({
    id: z.number(),
    email: z.string().email(),
});

pm.test("Response matches User shape", function () {
    const parsed = User.safeParse(pm.response.json());
    pm.expect(parsed.success).to.be.true;
});
